public async Task<bool> PurchaseTicketsAsync(int eventId, int purchaseQuantity)
{
    using (var context = new EventBookingContext())
    {
        var eventEntity = await context.Events
            .Where(e => e.EventId == eventId)
            .FirstOrDefaultAsync();

        if (eventEntity == null || purchaseQuantity <= 0)
            return false;

        bool success = false;

        await context.Database.BeginTransactionAsync();

        try
        {
            context.Entry(eventEntity).Reload();

            if (eventEntity.AvailableSeats >= purchaseQuantity)
