                eventEntity.AvailableSeats -= purchaseQuantity;
                await context.SaveChangesAsync();
                await context.Database.CommitTransactionAsync();
                success = true;
            }
            else
            {
                await context.Database.RollbackTransactionAsync();
            }
        }
        catch
        {
            await context.Database.RollbackTransactionAsync();
            throw;
        }

        return success;
    }
